import{_ as a,o as e,c as d,a4 as r}from"./chunks/framework.BybBnFXO.js";const c=JSON.parse('{"title":"星光效应","description":"","frontmatter":{"title":"星光效应","phenomenon":"asterism"},"headers":[],"relativePath":"zh/optical-phenomena/asterism.md","filePath":"zh/optical-phenomena/asterism.md","lastUpdated":1784177547000}'),i={name:"zh/optical-phenomena/asterism.md"};function o(n,t,h,s,l,p){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="星光效应" tabindex="-1">星光效应 <a class="header-anchor" href="#星光效应" aria-label="Permalink to &quot;星光效应&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>当宝石内部含有沿特定结晶方向平行排列的针状或管状包裹体时， 弧面切割下可见光从这些包裹体反射形成 4 射或 6 射星芒。最著名的 是 6 射星光红宝石/蓝宝石（刚玉族）；透辉石可呈 4 射星。星光 通常需要单点光源直射下观察最清晰，漫射光下会变得模糊。</p><h2 id="机制" tabindex="-1">机制 <a class="header-anchor" href="#机制" aria-label="Permalink to &quot;机制&quot;">​</a></h2><p>包体反射：针状金红石（TiO₂）按刚玉三方晶系的 c 轴 60°/120° 角相交排列。弧面切割的穹顶结构将反射光按出射方向引导，在视觉 上叠加为 6 道星线。星线交点位于宝石顶部圆顶最高点。</p><h2 id="示例宝石" tabindex="-1">示例宝石 <a class="header-anchor" href="#示例宝石" aria-label="Permalink to &quot;示例宝石&quot;">​</a></h2><table tabindex="0"><thead><tr><th>宝石</th><th>星线数</th><th>宿主矿物</th><th>包裹体</th></tr></thead><tbody><tr><td>Star Ruby / 星光红宝</td><td>6</td><td>Corundum</td><td>rutile (TiO₂)</td></tr><tr><td>Star Sapphire / 星光蓝宝</td><td>6</td><td>Corundum</td><td>rutile (TiO₂)</td></tr><tr><td>Star Diopside / 星光透辉石</td><td>4</td><td>Diopside</td><td>magnetite</td></tr><tr><td>Star Rose Quartz / 星光芙蓉石</td><td>6</td><td>Quartz</td><td>rutile</td></tr><tr><td>Star Garnet / 星光石榴石</td><td>4</td><td>Garnet</td><td>rutile / apatite</td></tr></tbody></table><p><em>详见<a href="./intro.html">光学现象总览</a>。</em></p>',8)])])}const u=a(i,[["render",o]]);export{c as __pageData,u as default};
